// Merge and deduplicate articles from multiple RSS feeds
const techItems = $('Tech News Feed').all();
const hnItems = $('Hacker News Feed').all();

const allArticles = [];
const seenUrls = new Set();

const processItems = (items, source) => {
  for (const item of items.slice(0, 10)) {
    const url = item.json.link || item.json.guid || '';
    if (url && !seenUrls.has(url)) {
      seenUrls.add(url);
      allArticles.push({
        title: item.json.title || 'Untitled',
        url,
        description: (item.json.contentSnippet || item.json.description || '').substring(0, 500),
        pubDate: item.json.pubDate || item.json.isoDate || '',
        source
      });
    }
  }
};

processItems(techItems, 'Ars Technica');
processItems(hnItems, 'Hacker News');

// Sort by date, newest first
allArticles.sort((a, b) => new Date(b.pubDate) - new Date(a.pubDate));

return [{ json: { articles: allArticles.slice(0, 15), count: allArticles.length, fetchedAt: new Date().toISOString() } }];

// Build the formatted daily digest
const aiResponse = $input.first().json.text || '';
const articles = $('Merge and Deduplicate').first().json.articles;
let scored = [];

try {
  const match = aiResponse.match(/\[[\s\S]*\]/);
  if (match) scored = JSON.parse(match[0]);
} catch (e) {
  scored = articles.map((a, i) => ({
    index: i + 1,
    title: a.title,
    summary: a.description.substring(0, 100),
    score: 5,
    category: 'other'
  }));
}

// Sort by score descending
scored.sort((a, b) => b.score - a.score);

// Build Slack-formatted digest
const today = new Date().toISOString().split('T')[0];
const topStories = scored.filter(s => s.score >= 7);
const otherStories = scored.filter(s => s.score < 7);

let slackText = `📰 *Daily News Digest — ${today}*\n\n`;

if (topStories.length > 0) {
  slackText += `*🔥 Top Stories*\n`;
  topStories.forEach(s => {
    const article = articles[s.index - 1];
    slackText += `• *${s.title}* (⭐ ${s.score}/10)\n  ${s.summary}\n  ${article ? article.url : ''}\n\n`;
  });
}

if (otherStories.length > 0) {
  slackText += `*📋 Other News*\n`;
  otherStories.forEach(s => {
    slackText += `• ${s.title} (${s.score}/10) — ${s.summary}\n`;
  });
}

// Build email HTML
let emailBody = `Daily News Digest — ${today}\n\n`;
scored.forEach(s => {
  const article = articles[s.index - 1];
  emailBody += `[${s.score}/10] ${s.title}\n${s.summary}\n${article ? article.url : ''}\n\n`;
});

return [{
  json: {
    slackText,
    emailBody,
    date: today,
    totalArticles: scored.length,
    topStoriesCount: topStories.length
  }
}];
